import {
  Children,
  isValidElement,
  useMemo,
  useState,
  type ComponentType,
  type ReactNode,
} from "react"
import {
  ChartContext,
  type ChartConfig,
  type ChartCtx,
  type Margins,
  type Row,
  type SeriesDef,
} from "./chart-context"
import { bandScale, linearScale, pointScale, seriesExtent } from "./scales"
import { isSpecies, type Species } from "./species"
import { useDimensions, useReducedMotion } from "./use-chart"

// Generous top/right: heads, hoods and mid-flick tongues need somewhere to
// exist beyond the last data point without leaving the canvas.
const DEFAULT_MARGINS: Margins = { top: 30, right: 34, bottom: 24, left: 36 }

// Fallback casting order when a series doesn't pick its own species.
const CAST: Species[] = ["garter", "python", "coral", "viper", "mamba", "boa"]

export type CartesianProps = {
  data: Row[]
  config: ChartConfig
  children?: ReactNode
  margins?: Partial<Margins>
  className?: string
  /** Chart-wide slither multiplier. 1 = honest, 2 = unhinged. */
  wiggle?: number
  onHoverChange?: (index: number | null) => void
}

type Layered = { back: ReactNode[]; svg: ReactNode[]; dom: ReactNode[] }

function partition(children: ReactNode): {
  layers: Layered
  series: SeriesDef[]
  xKey: string | null
} {
  const layers: Layered = { back: [], svg: [], dom: [] }
  const series: SeriesDef[] = []
  let xKey: string | null = null
  Children.forEach(children, (child) => {
    if (!isValidElement(child)) return
    const type = child.type as ComponentType & { layer?: string }
    const props = child.props as Record<string, unknown>
    if (type.layer === "series") {
      series.push({
        dataKey: String(props.dataKey),
        species: isSpecies(props.species)
          ? props.species
          : CAST[series.length % CAST.length],
        wiggle: typeof props.wiggle === "number" ? props.wiggle : undefined,
        hood: typeof props.hood === "number" ? props.hood : undefined,
      })
      return
    }
    if (typeof props.dataKey === "string" && xKey == null && type.layer === "svg")
      xKey = props.dataKey
    if (type.layer === "back") layers.back.push(child)
    else if (type.layer === "dom") layers.dom.push(child)
    else layers.svg.push(child)
  })
  return { layers, series, xKey }
}

/** Shared root for the cartesian snakes (line + bar). Owns measurement,
 * scales, hover scrubbing, and the three render layers: back SVG (grid),
 * the snake canvas, front SVG (axes), then DOM chrome (legend, HissTip). */
export function CartesianRoot({
  kind,
  Canvas,
  data,
  config,
  children,
  margins: marginsProp,
  className,
  wiggle,
  onHoverChange,
}: CartesianProps & { kind: "slither" | "cobra"; Canvas: ComponentType }) {
  const { ref, size } = useDimensions<HTMLDivElement>()
  const frozen = useReducedMotion()
  const [hoverIndex, setHoverIndex] = useState<number | null>(null)
  const [hoveredKey, setHoveredKey] = useState<string | null>(null)
  const [cursorX, setCursorX] = useState(0)

  const { layers, series, xKey } = partition(children)
  const seriesKey = JSON.stringify(series)

  const ctx: ChartCtx = useMemo(() => {
    const margins = { ...DEFAULT_MARGINS, ...marginsProp }
    const innerW = Math.max(0, size.width - margins.left - margins.right)
    const innerH = Math.max(0, size.height - margins.top - margins.bottom)
    const keys = series.map((s) => s.dataKey)
    const y = linearScale(seriesExtent(data, keys), [innerH, 0], 4)
    const band = kind === "cobra" ? bandScale(data.length, [0, innerW]) : null
    const point = pointScale(data.length, [0, innerW])
    return {
      kind,
      data,
      config,
      series,
      xKey,
      width: size.width,
      height: size.height,
      margins,
      innerW,
      innerH,
      xAt: band ? band.center : point,
      band,
      y,
      hoverIndex,
      setHoverIndex,
      hoveredKey,
      setHoveredKey,
      cursorX,
      wiggle: wiggle ?? 1,
      frozen,
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
    data,
    config,
    seriesKey,
    xKey,
    kind,
    size.width,
    size.height,
    hoverIndex,
    hoveredKey,
    cursorX,
    wiggle,
    frozen,
    JSON.stringify(marginsProp),
  ])

  const onMove = (clientX: number) => {
    const el = ref.current
    if (!el || data.length === 0) return
    const rect = el.getBoundingClientRect()
    const px = clientX - rect.left
    let best = 0
    let bestD = Infinity
    for (let i = 0; i < data.length; i++) {
      const d = Math.abs(ctx.margins.left + ctx.xAt(i) - px)
      if (d < bestD) {
        bestD = d
        best = i
      }
    }
    setCursorX(px)
    setHoverIndex(best)
    onHoverChange?.(best)
  }

  const ready = size.width > 0 && size.height > 0

  return (
    <ChartContext.Provider value={ctx}>
      <div
        ref={ref}
        className={className}
        style={{ position: "relative", width: "100%", height: "100%" }}
        onPointerMove={(e) => onMove(e.clientX)}
        onPointerLeave={() => {
          setHoverIndex(null)
          onHoverChange?.(null)
        }}
      >
        {ready && layers.back.length > 0 && (
          <svg
            width={size.width}
            height={size.height}
            style={{ position: "absolute", inset: 0, overflow: "visible" }}
            aria-hidden
          >
            <g transform={`translate(${ctx.margins.left},${ctx.margins.top})`}>
              {layers.back}
            </g>
          </svg>
        )}
        {ready && <Canvas />}
        {ready && (
          <svg
            width={size.width}
            height={size.height}
            style={{ position: "absolute", inset: 0, overflow: "visible" }}
            role="img"
            aria-label={`${kind === "cobra" ? "Bar" : "Line"} chart with ${series.length} snake${series.length === 1 ? "" : "s"}`}
          >
            <g transform={`translate(${ctx.margins.left},${ctx.margins.top})`}>
              {layers.svg}
            </g>
          </svg>
        )}
        {ready && layers.dom}
      </div>
    </ChartContext.Provider>
  )
}

import { useChart } from "./chart-context"

/** Horizontal guide lines. Subtle — snakes hate bright light. */
export function Grid({ vertical = false }: { vertical?: boolean }) {
  const { y, innerW, innerH, data, xAt } = useChart()
  return (
    <g>
      {y.ticks.map((t) => (
        <line
          key={t}
          x1={0}
          x2={innerW}
          y1={y(t)}
          y2={y(t)}
          style={{ stroke: "var(--sc-grid, rgba(190, 205, 180, 0.13))" }}
          strokeDasharray="3 5"
        />
      ))}
      {vertical &&
        data.map((_, i) => (
          <line
            key={i}
            x1={xAt(i)}
            x2={xAt(i)}
            y1={0}
            y2={innerH}
            style={{ stroke: "var(--sc-grid, rgba(190, 205, 180, 0.13))" }}
            strokeDasharray="3 5"
          />
        ))}
    </g>
  )
}
Grid.layer = "back" as const

import { useChart } from "./chart-context"

const label = {
  fill: "var(--sc-axis, #97a68f)",
  fontFamily: "var(--sc-mono, ui-monospace, monospace)",
  fontSize: 10,
  letterSpacing: "0.04em",
} as const

/** Category labels along the ground the snakes slither over.
 * `dataKey` is read by the chart root to label rows + tooltips. */
export function XAxis(_props: { dataKey: string }) {
  const { data, xKey, xAt, innerH, innerW } = useChart()
  const n = data.length
  // Thin labels when the terrarium is narrow.
  const every = Math.max(1, Math.ceil((n * 34) / Math.max(1, innerW)))
  return (
    <g>
      <line
        x1={0}
        x2={innerW}
        y1={innerH + 0.5}
        y2={innerH + 0.5}
        style={{ stroke: "var(--sc-axis-line, rgba(190, 205, 180, 0.3))" }}
      />
      {data.map((row, i) =>
        i % every === 0 ? (
          <text
            key={i}
            x={xAt(i)}
            y={innerH + 16}
            textAnchor="middle"
            style={label}
          >
            {String(xKey ? (row[xKey] ?? i) : i)}
          </text>
        ) : null
      )}
    </g>
  )
}
XAxis.layer = "svg" as const

export function YAxis({ format }: { format?: (v: number) => string }) {
  const { y } = useChart()
  const fmt = format ?? ((v: number) => (Math.abs(v) >= 1000 ? `${v / 1000}k` : `${v}`))
  return (
    <g>
      {y.ticks.map((t) => (
        <text
          key={t}
          x={-9}
          y={y(t) + 3}
          textAnchor="end"
          style={label}
        >
          {fmt(t)}
        </text>
      ))}
    </g>
  )
}
YAxis.layer = "svg" as const

import { useContext } from "react"
import { ChartContext, PolarContext } from "./chart-context"
import { skinOf, type Species } from "./species"

/** Tiny slithering swatch — a legend chip you can trust. */
export function Squiggle({ species, size = 22 }: { species: Species; size?: number }) {
  const skin = skinOf(species)
  const h = size * 0.55
  return (
    <svg width={size} height={h} viewBox={`0 0 ${size} ${h}`} aria-hidden>
      <path
        d={`M1 ${h / 2} q ${size * 0.18} ${-h * 0.7}, ${size * 0.36} 0 t ${size * 0.36} 0`}
        fill="none"
        stroke={skin.skin}
        strokeWidth={h * 0.34}
        strokeLinecap="round"
      />
      <circle cx={size - 2.5} cy={h / 2} r={h * 0.24} fill={skin.skin} />
      <circle cx={size - 1.8} cy={h / 2 - h * 0.09} r={h * 0.07} fill={skin.pupil} />
    </svg>
  )
}

type Entry = { key: string; label: string; species: Species }

/** Hover a chip and the other snakes politely fade. The chip's tooltip
 * (title) is the species' latin name, because this is a serious library. */
export function Legend({ align = "right" }: { align?: "left" | "center" | "right" }) {
  const cart = useContext(ChartContext)
  const polar = useContext(PolarContext)

  let entries: Entry[] = []
  let hoveredKey: string | null = null
  let setHoveredKey: (k: string | null) => void = () => {}

  if (cart) {
    entries = cart.series.map((s) => ({
      key: s.dataKey,
      label: cart.config[s.dataKey]?.label ?? s.dataKey,
      species: s.species,
    }))
    hoveredKey = cart.hoveredKey
    setHoveredKey = cart.setHoveredKey
  } else if (polar) {
    entries = polar.slices.map((s) => ({
      key: s.name,
      label: s.label,
      species: s.species,
    }))
    hoveredKey = polar.hoveredKey
    setHoveredKey = polar.setHoveredKey
  }

  return (
    <div
      style={{
        position: "absolute",
        top: 2,
        left: 0,
        right: 6,
        display: "flex",
        flexWrap: "wrap",
        gap: "4px 14px",
        justifyContent:
          align === "center" ? "center" : align === "left" ? "flex-start" : "flex-end",
        pointerEvents: "auto",
        fontFamily: "var(--sc-mono, ui-monospace, monospace)",
        fontSize: 11,
        color: "var(--sc-legend, #c9d2c0)",
      }}
    >
      {entries.map((e) => (
        <button
          key={e.key}
          type="button"
          title={skinOf(e.species).latin}
          onPointerEnter={() => setHoveredKey(e.key)}
          onPointerLeave={() => setHoveredKey(null)}
          onFocus={() => setHoveredKey(e.key)}
          onBlur={() => setHoveredKey(null)}
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 6,
            background: "none",
            border: "none",
            padding: 0,
            cursor: "default",
            color: "inherit",
            font: "inherit",
            opacity: hoveredKey && hoveredKey !== e.key ? 0.45 : 1,
            transition: "opacity 160ms",
          }}
        >
          <Squiggle species={e.species} />
          {e.label}
        </button>
      ))}
    </div>
  )
}
Legend.layer = "dom" as const

import { useContext } from "react"
import { ChartContext, PolarContext } from "./chart-context"
import { skinOf } from "./species"
import { Squiggle } from "./legend"

const panel: React.CSSProperties = {
  position: "absolute",
  pointerEvents: "none",
  background: "var(--sc-tip-bg, rgba(16, 22, 15, 0.94))",
  border: "1px solid var(--sc-tip-border, rgba(190, 205, 180, 0.25))",
  borderRadius: 6,
  padding: "7px 10px",
  fontFamily: "var(--sc-mono, ui-monospace, monospace)",
  fontSize: 11,
  color: "var(--sc-tip-fg, #e8e4d0)",
  boxShadow: "0 6px 18px rgba(0,0,0,0.45)",
  whiteSpace: "nowrap",
  zIndex: 3,
}

/** The tooltip. It hisses the values at you as you scrub. */
export function HissTip() {
  const cart = useContext(ChartContext)
  const polar = useContext(PolarContext)

  if (cart) {
    const { hoverIndex, data, series, config, xKey, cursorX, width } = cart
    if (hoverIndex == null || !data[hoverIndex]) return null
    const row = data[hoverIndex]
    const left = Math.min(Math.max(cursorX + 14, 4), Math.max(4, width - 210))
    return (
      <div style={{ ...panel, left, top: 30 }}>
        <div style={{ opacity: 0.65, marginBottom: 5 }}>
          {xKey ? String(row[xKey]) : `#${hoverIndex}`}{" "}
          <span style={{ opacity: 0.7, fontStyle: "italic" }}>sss…</span>
        </div>
        {series.map((s) => (
          <div
            key={s.dataKey}
            style={{ display: "flex", alignItems: "center", gap: 7, lineHeight: 1.7 }}
          >
            <Squiggle species={s.species} size={18} />
            <span style={{ opacity: 0.8 }}>
              {config[s.dataKey]?.label ?? s.dataKey}
            </span>
            <span style={{ marginLeft: "auto", paddingLeft: 12, fontWeight: 600 }}>
              {String(row[s.dataKey] ?? "–")}
            </span>
          </div>
        ))}
      </div>
    )
  }

  if (polar) {
    const { hoverSlice, slices, cursor, width } = polar
    if (hoverSlice == null || !slices[hoverSlice]) return null
    const s = slices[hoverSlice]
    const left = Math.min(Math.max(cursor.x + 14, 4), Math.max(4, width - 230))
    return (
      <div style={{ ...panel, left, top: Math.max(4, cursor.y - 44) }}>
        <div style={{ display: "flex", alignItems: "center", gap: 7 }}>
          <Squiggle species={s.species} size={18} />
          <span style={{ opacity: 0.8 }}>{s.label}</span>
          <span style={{ marginLeft: "auto", paddingLeft: 12, fontWeight: 600 }}>
            {s.value} · {(s.frac * 100).toFixed(0)}%
          </span>
        </div>
        <div style={{ opacity: 0.55, marginTop: 4, fontStyle: "italic" }}>
          {skinOf(s.species).latin}
        </div>
      </div>
    )
  }

  return null
}
HissTip.layer = "dom" as const
